import * as React from 'react';
import Box from '@mui/material/Box';
import Container from '@mui/material/Container';

import ImageList from '@mui/material/ImageList';
import ImageListItem from '@mui/material/ImageListItem';

// import * as Images from '../../assets/collections/daylight/*';

import Image from "../../assets/collections/daylight/Daylight-1.jpg";

import { useTheme, ThemeProvider } from '@mui/material/styles';


function Daylight () {
	// const theme = useTheme();
	const cache = {};

	function importAll(r) {
		r.keys().forEach((key) => (cache[key] = r(key)));
	};

	importAll(require.context('../../assets/collections/daylight', false, /\.jpg/));
	const images = Object.entries(cache).map(module => module[1]);

	// React.useEffect(() => {
	// 	console.log(images);
	// },[])

	return (
		<>
			{/* <ImageList sx={{ width: '100wh', height: '100vh', margin: '15% 10% 10% 10%', '&::-webkit-scrollbar': {display: 'none'} }} gap={10} cols={1} rowHeight={'auto'}>
				{images.map((item) => (
					<ImageListItem key={item}>
						<img src={`${item}?w=400&h=400&fit=crop&auto=format`}/>
					</ImageListItem>
				))}
			</ImageList> */}
			{/* <ThemeProvider theme={theme}> */}
			<Box
				display='flex'
				flexDirection='column'
				justifyContent='center'
				gap={2}
				sx={{
					margin: {
						// xxs: '20%',
						xs: '10px',
						lg: '10% 20% 10%'
					}
					// margin: {
					// 	xs: '25% 20px 10%',
					// 	md: '10% 50px 10%',
					// 	lg: '12% 20px 10%',
					// }
				}}
			>
				{images.map((item) => (
					<Box
						component={'img'}
						height={'300px'}
						width={'100wh'}
						src={item}
						flex={1}
						sx={{  }}
					/>
				))}
			</Box>
			{/* </ThemeProvider> */}
		</>
	)
}

export default Daylight;
